// Validate input data - n8n webhook format
const webhookData = $input.first().json;

// Log incoming webhook data for debugging
console.log('=== INCOMING WEBHOOK DATA ===');
console.log('Raw webhook data:', JSON.stringify(webhookData, null, 2));

// Extract body from webhook data
const data = webhookData.body || webhookData;

console.log('=== EXTRACTED BODY DATA ===');
console.log('Body data:', JSON.stringify(data, null, 2));
console.log('Data type:', typeof data);
console.log('Data keys:', Object.keys(data || {}));
console.log('Action:', data?.action);
console.log('UserId:', data?.userId);
console.log('Email:', data?.email);
console.log('Profile:', data?.profile);
console.log('Metadata:', data?.metadata);
console.log('Timestamp:', data?.timestamp);
console.log('==========================');

// Check required fields with better error messages
if (!data?.action) {
  console.log('❌ Missing action field');
  throw new Error('Missing required field: action');
}

if (!data?.userId) {
  console.log('❌ Missing userId field');
  throw new Error('Missing required field: userId');
}

// Validate action
const validActions = ['read', 'create', 'update', 'get', 'delete'];
if (!validActions.includes(data.action)) {
  console.log('❌ Invalid action:', data.action);
  throw new Error(`Invalid action: ${data.action}. Must be one of: ${validActions.join(', ')}`);
}

// Sanitize and prepare data - PRESERVE ALL FIELDS from body!
// CRITICAL: Include dailyUsage - it's now a separate column, NOT in metadata!
const sanitizedData = {
  action: data.action,
  userId: data.userId,
  email: data.email || '',
  tier: data.tier, // Preserve tier if provided
  dailyUsage: data.dailyUsage, // CRITICAL: Preserve dailyUsage (separate column!)
  profile: data.profile || {},
  metadata: data.metadata || {},
  lastLogin: data.lastLogin, // Preserve lastLogin if provided
  status: data.status, // Preserve status if provided
  timestamp: data.timestamp || Date.now()
};

console.log('✅ Data validation passed');
console.log('Sanitized data:', JSON.stringify(sanitizedData, null, 2));

return { json: sanitizedData };

// Check if account already exists before creating
const items = $input.all();
const data = items[0].json; // Data from Validate Data
const existingAccount = items.length > 1 && items[1]?.json ? items[1].json : null;

console.log('🔍 Checking for existing account with email:', data.email);
console.log('📥 Existing account data:', existingAccount);

// If account already exists, return error
if (existingAccount && existingAccount.email && existingAccount.email.toLowerCase() === data.email.toLowerCase()) {
  console.log('❌ Account already exists with email:', data.email);
  throw new Error(`Account already exists with email: ${data.email}. Use 'update' action instead.`);
}

// Create new account only if it doesn't exist
const now = new Date().toISOString();

const newAccount = {
  userId: data.userId,
  email: data.email,
  tier: data.tier || 'free',
  createdAt: now,
  lastLogin: now,
  profile: typeof data.profile === 'string' ? data.profile : JSON.stringify(data.profile || {}),
  metadata: typeof data.metadata === 'string' ? data.metadata : JSON.stringify(data.metadata || {}),
  status: data.status || 'active'
};

console.log('✅ Creating new account:', JSON.stringify(newAccount, null, 2));

return { json: newAccount };

