// Format Response for Send Response Node
// This node prepares the response data from Update Google Sheets
const items = $input.all();
const accountData = items[0].json;

// Get action from Validate Data node (if available)
let action = 'update';
try {
  const validateData = $('Validate Data').first()?.json;
  if (validateData && validateData.action) {
    action = validateData.action;
  }
} catch (e) {
  // Fallback to 'update' if Validate Data not available
  action = 'update';
}

const isReadOperation = action === 'get' || action === 'read';
const message = isReadOperation ? 'Account retrieved successfully' : 'Account updated successfully';

// Helper: Parse dailyUsage (can be string, object, or empty string)
let dailyUsage = accountData.dailyUsage || accountData.DailyUsage || null;
if (dailyUsage && typeof dailyUsage === 'string' && dailyUsage.trim() !== '') {
  try {
    dailyUsage = JSON.parse(dailyUsage);
  } catch (e) {
    // If parsing fails, keep as string
    dailyUsage = dailyUsage;
  }
} else if (dailyUsage === '' || dailyUsage === null || dailyUsage === undefined) {
  dailyUsage = null;
}

// Helper: Parse profile
let profile = accountData.profile || {};
if (typeof profile === 'string' && profile.trim() !== '') {
  try {
    profile = JSON.parse(profile);
  } catch (e) {
    profile = {};
  }
}

// Helper: Parse metadata
let metadata = accountData.metadata || {};
if (typeof metadata === 'string' && metadata.trim() !== '') {
  try {
    metadata = JSON.parse(metadata);
  } catch (e) {
    metadata = {};
  }
}

// Build response object
const response = {
  success: true,
  account: {
    userId: accountData.userId || accountData.UserID,
    email: accountData.email || accountData.Email,
    tier: accountData.tier || accountData.Tier,
    createdAt: accountData.createdAt || accountData.CreatedAt,
    lastLogin: accountData.lastLogin || accountData.LastLogin,
    dailyUsage: dailyUsage,
    profile: profile,
    metadata: metadata,
    status: accountData.status || accountData.Status
  },
  message: message,
  timestamp: new Date().toISOString()
};

console.log('📤 Formatted response:', JSON.stringify(response, null, 2));

return { json: response };

// Enhanced Account Update - Deep Merge for nested settings!
// CRITICAL: createdAt MUST be preserved from existing account data - NEVER overwrite on update!
// CRITICAL: For GET/READ operations, just pass through data WITHOUT updating!
const items = $input.all();
console.log('📥 Total items:', items.length);

if (!items || items.length === 0) {
  throw new Error('No input data');
}

// Webhook data (items[0] - from Validate Data node)
const body = items[0].json;

// CRITICAL: Check if this is a GET/READ operation - if so, just pass through data!
const action = body.action || 'get';
if (action === 'get' || action === 'read') {
  console.log('✅ [GET/READ] Pass-through mode - no update will be performed');
  // For GET/READ, use data from Read Accounts (items[1] if exists, otherwise items[0])
  const readData = items.length > 1 && items[1]?.json ? items[1].json : items[0].json;
  return { json: readData };
}

console.log('📥 Incoming data from Validate Data:', JSON.stringify(body, null, 2));

// CRITICAL: Validate required fields
// userId is ALWAYS required
// email can be empty string for updates (will be preserved from existing account)
if (!body.userId) {
  throw new Error('Missing required field: userId');
}

// For updates, email can be empty (will use existing email from Google Sheets)
// Only require email if it's a new account creation
if (!body.email && body.action === 'create') {
  throw new Error('Missing required field: email (required for account creation)');
}

// Lookup data (items[1]) - existing Google Sheets data
let lookupData = null;
if (items.length > 1 && items[1]?.json && items[1].json.userId) {
  lookupData = items[1].json;
  console.log('📥 Existing data from Google Sheets:', JSON.stringify(lookupData, null, 2));
  console.log('🔍 Existing createdAt:', lookupData.createdAt || 'NOT FOUND');
} else {
  console.log('ℹ️ No existing account - creating new row');
}

// Helper: Parse JSON safely
function parseJSON(value, fallback = {}) {
  if (!value) return fallback;
  if (typeof value === 'object' && !Array.isArray(value)) return value;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (trimmed === '' || trimmed === '""') return fallback;
    try {
      const parsed = JSON.parse(trimmed);
      if (typeof parsed === 'object' && !Array.isArray(parsed)) {
        return parsed;
      }
    } catch (e) {
      console.warn('⚠️ Parse error:', e.message);
    }
  }
  return fallback;
}

// CRITICAL: Deep merge function for nested objects
function deepMerge(target, source) {
  const result = { ...target };

  for (const key in source) {
    if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
      result[key] = deepMerge(target[key] || {}, source[key]);
    } else {
      result[key] = source[key];
    }
  }

  return result;
}

// Parse existing data
let existingProfile = {};
let existingMetadata = {};

if (lookupData) {
  existingProfile = parseJSON(lookupData.profile, {});
  existingMetadata = parseJSON(lookupData.metadata, {});
  // CRITICAL: Remove dailyUsage from existingMetadata if present (migration support)
  // dailyUsage should be in its own column, not in metadata!
  if (existingMetadata.dailyUsage) {
    console.warn('⚠️ [MIGRATION] Removing dailyUsage from existingMetadata - should be in separate column');
    const { dailyUsage, ...metadataWithoutDailyUsage } = existingMetadata;
    existingMetadata = metadataWithoutDailyUsage;
  }
  console.log('📦 Existing profile:', existingProfile);
  console.log('📦 Existing metadata:', existingMetadata);
}

// Parse incoming data
const incomingProfile = parseJSON(body.profile, {});
const incomingMetadata = parseJSON(body.metadata, {});

console.log('📥 Incoming profile:', incomingProfile);
console.log('📥 Incoming metadata:', incomingMetadata);

// SMART MERGE: Only update if incoming data is not empty
const hasProfileData = Object.keys(incomingProfile).length > 0;
const hasMetadataSettings = incomingMetadata.settings && Object.keys(incomingMetadata.settings).length > 0;
const hasOtherMetadata = Object.keys(incomingMetadata).some(key => key !== 'settings' && incomingMetadata[key] !== undefined);

console.log('📊 Incoming data check:', {
  hasProfileData,
  hasMetadataSettings,
  hasOtherMetadata
});

// Build updated profile (only if new data provided)
const updatedProfile = hasProfileData
  ? { ...existingProfile, ...incomingProfile }
  : existingProfile;

// Build updated metadata (DEEP MERGE for nested settings!)
let updatedMetadata = { ...existingMetadata };

// Update settings only if provided - USE DEEP MERGE!
if (hasMetadataSettings) {
  updatedMetadata.settings = deepMerge(
    existingMetadata.settings || {},
    incomingMetadata.settings
  );
  console.log('✅ Settings updated (deep merge)');
}

// Update other metadata fields
// CRITICAL: Exclude ALL fields that have their own columns!
// Single Source of Truth: Fields with own columns should NOT be in metadata
// Google Sheets columns: userId, email, tier, createdAt, lastLogin, profile, dailyUsage, status
const COLUMN_FIELDS = ['userId', 'email', 'tier', 'createdAt', 'lastLogin', 'profile', 'dailyUsage', 'status', 'UserID', 'Email', 'Tier', 'CreatedAt', 'LastLogin', 'Profile', 'DailyUsage', 'Status'];
if (hasOtherMetadata) {
  Object.keys(incomingMetadata).forEach(key => {
    // Skip 'settings' (handled separately) AND all column fields (have own columns!)
    if (key !== 'settings' && !COLUMN_FIELDS.includes(key)) {
      updatedMetadata[key] = incomingMetadata[key];
    } else if (COLUMN_FIELDS.includes(key)) {
      console.warn(`⚠️ [METADATA CLEANER] Skipping duplicate field '${key}' - has own column in Google Sheets`);
    }
  });
  console.log('✅ Metadata updated (duplicate fields excluded - single source of truth)');
}

console.log('🔄 Final merged data:');
console.log('  profile:', updatedProfile);
console.log('  metadata:', updatedMetadata);

// CRITICAL: createdAt handling - MUST preserve from existing account!
// n8n Google Sheets appendOrUpdate behavior:
// - If field is in mapping and has value → updates the field
// - If field is in mapping but is null/undefined → might delete the field!
// - If field is NOT in output → field is not updated (preserved)
// Solution: Only include createdAt in output if it has a valid value!
// - For new accounts: Always set createdAt
// - For existing accounts: Only include if lookupData.createdAt has a valid value (not null/undefined/empty)
let createdAtValue = null;
let shouldIncludeCreatedAt = false;

if (lookupData) {
  // Account exists - check if createdAt has a valid value
  if (lookupData.hasOwnProperty('createdAt') && lookupData.createdAt && lookupData.createdAt.trim && lookupData.createdAt.trim() !== '') {
    // Valid createdAt exists - preserve it!
    createdAtValue = lookupData.createdAt;
    shouldIncludeCreatedAt = true;
    console.log('✅ Preserving existing createdAt from lookupData:', createdAtValue);
  } else {
    // createdAt is empty/null/undefined - DO NOT include in output to preserve existing value in Google Sheets!
    shouldIncludeCreatedAt = false;
    console.warn('⚠️ Account exists but createdAt is empty/null in lookupData - will NOT include in output (preserves existing in Google Sheets)');
  }
} else {
  // New account - create createdAt
  createdAtValue = new Date().toISOString();
  shouldIncludeCreatedAt = true;
  console.log('🆕 Creating new createdAt for new account:', createdAtValue);
}

// CRITICAL: dailyUsage handling - separate column, NOT in metadata!
// dailyUsage should be in its own column for better performance and data flow
// IMPORTANT: If body.dailyUsage is provided, ALWAYS include it in output (even if empty object!)
// If not provided, preserve existing value from lookupData if it exists
let dailyUsageValue = null;
let shouldIncludeDailyUsage = false;

// Check if dailyUsage is explicitly provided in the request
if (body.hasOwnProperty('dailyUsage')) {
  // dailyUsage is explicitly provided (even if null/undefined/empty object)
  shouldIncludeDailyUsage = true;
  if (body.dailyUsage !== null && body.dailyUsage !== undefined) {
    // Has a value - stringify if object
    dailyUsageValue = typeof body.dailyUsage === 'string' 
      ? body.dailyUsage 
      : JSON.stringify(body.dailyUsage);
    console.log('✅ Using incoming dailyUsage:', dailyUsageValue.substring(0, 100));
  } else {
    // Explicitly null/undefined - set to empty string to clear column
    dailyUsageValue = '';
    console.log('ℹ️ Incoming dailyUsage is null/undefined - will clear column');
  }
} else if (lookupData && lookupData.hasOwnProperty('dailyUsage')) {
  // No incoming dailyUsage, but existing data in Google Sheets - preserve it!
  shouldIncludeDailyUsage = true;
  dailyUsageValue = lookupData.dailyUsage || '';
  console.log('✅ Preserving existing dailyUsage from lookupData');
} else {
  // No dailyUsage provided and no existing value - don't include in output
  // This prevents Google Sheets from clearing/updating the column
  console.log('ℹ️ No dailyUsage provided or found - will not update column (preserves existing)');
}

// Build output for Google Sheets
// CRITICAL: Always include createdAt in output when account exists (to preserve it!)
// dailyUsage is now a separate column, NOT in metadata!
// CRITICAL: Use existing email from lookupData if body.email is empty (for updates)
const outputEmail = body.email && body.email.trim() !== '' 
  ? body.email 
  : (lookupData?.email || body.email || '');

const output = {
  userId: body.userId,
  email: outputEmail,
  tier: body.tier || lookupData?.tier || 'free',
  lastLogin: body.lastLogin || body.timestamp || new Date().toISOString(),
  profile: JSON.stringify(updatedProfile),
  metadata: JSON.stringify(updatedMetadata),
  status: body.status || lookupData?.status || 'active'
};

// CRITICAL: Only include createdAt in output if it has a valid value!
// This prevents Google Sheets from deleting/overwriting createdAt when it's empty/null
if (shouldIncludeCreatedAt && createdAtValue) {
  output.createdAt = createdAtValue;
}

// CRITICAL: Include dailyUsage in output if it was provided OR if we need to preserve existing value!
// This ensures dailyUsage is written to Google Sheets when provided
if (shouldIncludeDailyUsage) {
  output.dailyUsage = dailyUsageValue !== null && dailyUsageValue !== undefined ? dailyUsageValue : '';
}

console.log('📤 Output for Google Sheets:', {
  userId: output.userId,
  email: output.email,
  hasCreatedAt: !!output.createdAt,
  createdAt: output.createdAt,
  hasDailyUsage: !!output.dailyUsage,
  dailyUsageLength: output.dailyUsage?.length || 0,
  profileLength: output.profile.length,
  metadataLength: output.metadata.length,
  lastLogin: output.lastLogin
});

return { json: output };
